// Check enrichment quality — did Lusha return useful data?
const lusha = $json;
const crm = $('New Contact Created in HubSpot').first().json;

const hasPhone = !!lusha.primaryPhone;
const hasTitle = !!lusha.jobTitle;
const hasCompany = !!lusha.companyName;
const fieldsFound = [hasPhone, hasTitle, hasCompany].filter(Boolean).length;

return { json: {
  contactId: crm.objectId,
  email: crm.properties?.email,
  // Lusha data
  firstName: lusha.firstName || crm.properties?.firstname || '',
  lastName: lusha.lastName || crm.properties?.lastname || '',
  phone: lusha.primaryPhone || '',
  jobTitle: lusha.jobTitle || '',
  seniority: lusha.seniority || '',
  linkedinUrl: lusha.linkedinProfile || '',
  company: lusha.companyName || '',
  companyDomain: lusha.companyDomain || '',
  industry: lusha.companyMainIndustry || '',
  companySize: Array.isArray(lusha.companySize) ? lusha.companySize[1] : '',
  location: lusha.companyLocation || '',
  // Quality metadata
  wasEnriched: fieldsFound >= 2,
  fieldsFound,
  enrichedAt: new Date().toISOString()
} };

// Check if contact is high seniority (VP, Director, C-Suite)
const seniority = ($json.seniority || '').toLowerCase();
const isHighSeniority = ['vp', 'vice president', 'director', 'c-suite', 'cxo', 'founder', 'owner', 'head'].some(s => seniority.includes(s));
return { json: { ...$json, isHighSeniority } };

